class SAMLResponseParser:
    """Parses and extracts data from SAML Response XML."""

    def __init__(self, xml_doc):
        self.xml_doc = xml_doc
        self.root = xml_doc

    @classmethod
    def from_base64(cls, encoded_response):
        """Decode a base64-encoded SAML response and parse the XML."""
        try:
            xml_bytes = base64.b64decode(encoded_response)
        except Exception as e:
            raise SAMLError(f"Failed to base64-decode SAML response: {e}")

        try:
            parser = etree.XMLParser(
                remove_blank_text=False,
                resolve_entities=False,
                dtd_validation=False,
                no_network=True,
                huge_tree=False,
            )
            doc = etree.fromstring(xml_bytes, parser=parser)
        except etree.XMLSyntaxError as e:
            raise SAMLError(f"Failed to parse SAML response XML: {e}")

        return cls(doc)

    def get_issuer(self):
        """Extract the Issuer from the Response."""
        issuer = self.root.find("saml:Issuer", NAMESPACES)
        if issuer is not None:
            return issuer.text.strip() if issuer.text else None
        return None

    def get_status_code(self):
        """Extract the StatusCode Value from the Response."""
        status_code = self.root.find(
            "samlp:Status/samlp:StatusCode", NAMESPACES
        )
        if status_code is not None:
            return status_code.get("Value")
        return None

    def get_assertions(self):
        """Extract all Assertion elements."""
        return self.root.findall("saml:Assertion", NAMESPACES)

    def get_response_id(self):
        return self.root.get("ID")

    def get_destination(self):
        return self.root.get("Destination")

    def get_in_response_to(self):
        return self.root.get("InResponseTo")

    def get_issue_instant(self):
        return self.root.get("IssueInstant")


class SAMLAssertionParser:
    """Extracts user attributes and conditions from a SAML Assertion."""

    def __init__(self, assertion_element):
        self.assertion = assertion_element

    def get_subject_name_id(self):
        """Extract the NameID from Subject."""
        name_id = self.assertion.find(
            "saml:Subject/saml:NameID", NAMESPACES
        )
        if name_id is not None:
            return {
                "value": name_id.text.strip() if name_id.text else None,
                "format": name_id.get("Format"),
                "sp_name_qualifier": name_id.get("SPNameQualifier"),
                "name_qualifier": name_id.get("NameQualifier"),
            }
        return None

    def get_session_index(self):
        """Extract session index from AuthnStatement."""
        authn_stmt = self.assertion.find(
            "saml:AuthnStatement", NAMESPACES
        )
        if authn_stmt is not None:
            return authn_stmt.get("SessionIndex")
        return None

    def get_authn_context_class_ref(self):
        """Extract the authentication context class reference."""
        ref = self.assertion.find(
            "saml:AuthnStatement/saml:AuthnContext/saml:AuthnContextClassRef",
            NAMESPACES,
        )
        if ref is not None:
            return ref.text.strip() if ref.text else None
        return None

    def get_conditions(self):
        """Extract Conditions element attributes."""
        conditions = self.assertion.find("saml:Conditions", NAMESPACES)
        if conditions is None:
            return None

        result = {
            "not_before": conditions.get("NotBefore"),
            "not_on_or_after": conditions.get("NotOnOrAfter"),
            "audiences": [],
        }

        for audience in conditions.findall(
            "saml:AudienceRestriction/saml:Audience", NAMESPACES
        ):
            if audience.text:
                result["audiences"].append(audience.text.strip())

        return result

    def get_subject_confirmation_data(self):
        """Extract SubjectConfirmationData attributes."""
        scd = self.assertion.find(
            "saml:Subject/saml:SubjectConfirmation/saml:SubjectConfirmationData",
            NAMESPACES,
        )
        if scd is not None:
            return {
                "not_on_or_after": scd.get("NotOnOrAfter"),
                "recipient": scd.get("Recipient"),
                "in_response_to": scd.get("InResponseTo"),
            }
        return None

    def get_attributes(self):
        """Extract all attributes from the AttributeStatement."""
        attributes = {}
        attr_statement = self.assertion.find(
            "saml:AttributeStatement", NAMESPACES
        )
        if attr_statement is None:
            return attributes

        for attr in attr_statement.findall("saml:Attribute", NAMESPACES):
            attr_name = attr.get("Name")
            attr_friendly_name = attr.get("FriendlyName")
            values = []
            for val in attr.findall("saml:AttributeValue", NAMESPACES):
                if val.text:
                    values.append(val.text.strip())

            key = attr_friendly_name or attr_name
            if key:
                attributes[key] = values if len(values) != 1 else values[0]

        return attributes


class SAMLSignatureValidator:
    """Validates XML Digital Signatures in SAML responses."""

    def __init__(self, idp_cert_pem):
        self.idp_cert_pem = idp_cert_pem.encode("utf-8") if isinstance(
            idp_cert_pem, str
        ) else idp_cert_pem
        try:
            self.certificate = load_pem_x509_certificate(self.idp_cert_pem)
            self.public_key = self.certificate.public_key()
        except Exception as e:
            raise SAMLError(f"Failed to load IdP certificate: {e}")

    def _get_c14n_method(self, algorithm_uri):
        """Map canonicalization algorithm URI to lxml method."""
        exclusive = algorithm_uri in (C14N_EXCLUSIVE, C14N_EXCLUSIVE_WITH_COMMENTS)
        with_comments = algorithm_uri in (
            C14N_EXCLUSIVE_WITH_COMMENTS,
            "http://www.w3.org/TR/2001/REC-xml-c14n-20010315#WithComments",
        )
        return exclusive, with_comments

    def _get_hash_algorithm(self, algorithm_uri):
        """Map digest/signature algorithm URI to a cryptography hash."""
        algo_map = {
            "sha1": hashes.SHA1(),
            "sha256": hashes.SHA256(),
            "sha384": hashes.SHA384(),
            "sha512": hashes.SHA512(),
        }
        uri_lower = algorithm_uri.lower()
        for name, algo in algo_map.items():
            if name in uri_lower:
                return algo
        raise SAMLError(f"Unsupported algorithm: {algorithm_uri}")

    def _canonicalize(self, node, exclusive, inclusive_ns_prefixes=None):
        """Canonicalize an XML node."""
        try:
            return etree.tostring(
                node,
                method="c14n2" if not exclusive else "c14n",
                exclusive=exclusive,
                inclusive_ns_prefixes=inclusive_ns_prefixes,
            )
        except TypeError:
            # Fallback for older lxml versions
            return etree.tostring(
                node,
                method="c14n",
                exclusive=exclusive,
                inclusive_ns_prefixes=inclusive_ns_prefixes,
            )

    def validate_signature(self, signed_element):
        """
        Validate the XML digital signature on a signed element.

        This validates:
        1. A Signature element exists
        2. The Reference URI points to the signed element
        3. The digest of the referenced content matches
        4. The signature over SignedInfo is valid using the IdP certificate
        """
        signature = signed_element.find("ds:Signature", NAMESPACES)
        if signature is None:
            raise SAMLError("No Signature element found in the signed element")

        signed_info = signature.find("ds:SignedInfo", NAMESPACES)
        if signed_info is None:
            raise SAMLError("No SignedInfo element found in Signature")

        # Extract canonicalization method for SignedInfo
        c14n_method = signed_info.find(
            "ds:CanonicalizationMethod", NAMESPACES
        )
        if c14n_method is None:
            raise SAMLError("No CanonicalizationMethod found")
        c14n_algorithm = c14n_method.get("Algorithm")
        exclusive, with_comments = self._get_c14n_method(c14n_algorithm)

        # Extract inclusive namespace prefixes if present
        inclusive_ns = c14n_method.find("ec:InclusiveNamespaces", {
            "ec": C14N_EXCLUSIVE
        })
        inclusive_ns_prefixes = None
        if inclusive_ns is not None:
            prefix_list = inclusive_ns.get("PrefixList", "")
            if prefix_list.strip():
                inclusive_ns_prefixes = prefix_list.strip().split()

        # Extract signature method
        sig_method = signed_info.find("ds:SignatureMethod", NAMESPACES)
        if sig_method is None:
            raise SAMLError("No SignatureMethod found")
        sig_algorithm = sig_method.get("Algorithm")
        sig_hash = self._get_hash_algorithm(sig_algorithm)

        # Extract and validate each Reference
        references = signed_info.findall("ds:Reference", NAMESPACES)
        if not references:
            raise SAMLError("No Reference elements found in SignedInfo")

        for reference in references:
            self._validate_reference(reference, signed_element, exclusive)

        # Validate the signature value over the canonicalized SignedInfo
        signature_value_elem = signature.find("ds:SignatureValue", NAMESPACES)
        if signature_value_elem is None or not signature_value_elem.text:
            raise SAMLError("No SignatureValue found")

        signature_value = base64.b64decode(
            signature_value_elem.text.strip().replace("\n", "").replace(" ", "")
        )

        # Canonicalize SignedInfo
        c14n_signed_info = self._canonicalize(
            signed_info, exclusive, inclusive_ns_prefixes
        )

        # Verify the signature
        try:
            self.public_key.verify(
                signature_value,
                c14n_signed_info,
                padding.PKCS1v15(),
                sig_hash,
            )
        except Exception as e:
            raise SAMLError(f"Signature verification failed: {e}")

        return True

    def _validate_reference(self, reference, signed_element, exclusive):
        """Validate a single Reference in the SignedInfo."""
        uri = reference.get("URI", "")

        # Determine which element the reference points to
        if uri.startswith("#"):
            ref_id = uri[1:]
            signed_elem_id = signed_element.get("ID")
            if signed_elem_id != ref_id:
                # Search within the tree for the element
                found = signed_element.xpath(
                    f'//*[@ID="{ref_id}"]'
                )
                if not found:
                    raise SAMLError(
                        f"Reference URI {uri} does not match any element"
                    )
                referenced_element = found[0]
            else:
                referenced_element = signed_element
        elif uri == "":
            referenced_element = signed_element
        else:
            raise SAMLError(f"Unsupported Reference URI format: {uri}")

        # Apply transforms
        transforms = reference.find("ds:Transforms", NAMESPACES)
        transform_list = []
        if transforms is not None:
            transform_list = transforms.findall("ds:Transform", NAMESPACES)

        # Process transforms to get the canonical form
        transformed_data = self._apply_transforms(
            referenced_element, transform_list
        )

        # Extract digest method and value
        digest_method = reference.find("ds:DigestMethod", NAMESPACES)
        if digest_method is None:
            raise SAMLError("No DigestMethod found in Reference")
        digest_algorithm = digest_method.get("Algorithm")
        digest_hash = self._get_hash_algorithm(digest_algorithm)

        digest_value_elem = reference.find("ds:DigestValue", NAMESPACES)
        if digest_value_elem is None or not digest_value_elem.text:
            raise SAMLError("No DigestValue found in Reference")

        expected_digest = base64.b64decode(
            digest_value_elem.text.strip().replace("\n", "").replace(" ", "")
        )

        # Compute digest
        if isinstance(digest_hash, hashes.SHA256):
            computed = hashlib.sha256(transformed_data).digest()
        elif isinstance(digest_hash, hashes.SHA1):
            computed = hashlib.sha1(transformed_data).digest()
        elif isinstance(digest_hash, hashes.SHA384):
            computed = hashlib.sha384(transformed_data).digest()
        elif isinstance(digest_hash, hashes.SHA512):
            computed = hashlib.sha512(transformed_data).digest()
        else:
            raise SAMLError(f"Unsupported digest algorithm: {digest_algorithm}")

        if not hmac.compare_digest(computed, expected_digest):
            raise SAMLError("Digest value mismatch - content may be tampered")

    def _apply_transforms(self, element, transform_list):
        """Apply the specified transforms and return the resulting bytes."""
        # Default: exclusive c14n
        transform_exclusive = True
        transform_ns_prefixes = None
        enveloped = False

        for transform in transform_list:
            algorithm = transform.get("Algorithm", "")

            if "enveloped-signature" in algorithm.lower():
                enveloped = True
            elif "exc-c14n" in algorithm.lower() or "xml-exc-c14n" in algorithm.lower():
                transform_exclusive = True
                inc_ns = transform.find("ec:InclusiveNamespaces", {
                    "ec": C14N_EXCLUSIVE
                })
                if inc_ns is not None:
                    pl = inc_ns.get("PrefixList", "")
                    if pl.strip():
                        transform_ns_prefixes = pl.strip().split()
            elif "c14n" in algorithm.lower():
                transform_exclusive = False

        # If enveloped-signature transform, remove Signature from a copy
        if enveloped:
            import copy
            element_copy = copy.deepcopy(element)
            sigs = element_copy.findall("ds:Signature", NAMESPACES)
            for sig in sigs:
                sig.getparent().remove(sig)
            return self._canonicalize(
                element_copy, transform_exclusive, transform_ns_prefixes
            )
        else:
            return self._canonicalize(
                element, transform_exclusive, transform_ns_prefixes
            )


class SAMLServiceProvider:
    """Main SAML Service Provider class that handles SSO flow."""

    def __init__(self, config):
        self.config = config
        self.signature_validator = SAMLSignatureValidator(config["idp_cert_pem"])

    def generate_authn_request_url(self, relay_state=None):
        """Generate the SAML AuthnRequest URL for redirect binding."""
        request_id = f"_{''.join(f'{b:02x}' for b in hashlib.sha256(str(datetime.now(timezone.utc).timestamp()).encode()).digest()[:16])}"
        issue_instant = datetime.now(timezone.utc).strftime(
            "%Y-%m-%dT%H:%M:%SZ"
        )

        authn_request = f"""<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{self.config['idp_sso_url']}"
    AssertionConsumerServiceURL="{self.config['sp_acs_url']}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{self.config['sp_entity_id']}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>"""

        # Deflate and base64 encode for redirect binding
        compressed = zlib.compress(authn_request.encode("utf-8"))[2:-4]
        encoded = base64.b64encode(compressed).decode("utf-8")

        params = {"SAMLRequest": encoded}
        if relay_state:
            params["RelayState"] = relay_state

        url = f"{self.config['idp_sso_url']}?{urlencode(params)}"
        return url, request_id

    def process_response(self, saml_response_b64, expected_request_id=None):
        """
        Process and validate a SAML Response.

        Returns a dict with user information if valid.
        """
        # Parse the response
        parser = SAMLResponseParser.from_base64(saml_response_b64)

        # 1. Validate status
        status = parser.get_status_code()
        if status != "urn:oasis:names:tc:SAML:2.0:status:Success":
            raise SAMLError(f"SAML Response status is not Success: {status}")

        # 2. Validate issuer matches expected IdP
        issuer = parser.get_issuer()
        if issuer != self.config["idp_entity_id"]:
            raise SAMLError(
                f"Response Issuer mismatch. Expected: {self.config['idp_entity_id']}, "
                f"Got: {issuer}"
            )

        # 3. Validate destination
        destination = parser.get_destination()
        if destination and destination != self.config["sp_acs_url"]:
            raise SAMLError(
                f"Response Destination mismatch. Expected: {self.config['sp_acs_url']}, "
                f"Got: {destination}"
            )

        # 4. Check InResponseTo if we have an expected request ID
        if expected_request_id:
            in_response_to = parser.get_in_response_to()
            if in_response_to and in_response_to != expected_request_id:
                raise SAMLError(
                    f"InResponseTo mismatch. Expected: {expected_request_id}, "
                    f"Got: {in_response_to}"
                )

        # 5. Validate signature on Response or Assertion
        response_signed = False
        try:
            self.signature_validator.validate_signature(parser.root)
            response_signed = True
        except SAMLError:
            pass  # Signature might be on the Assertion instead

        # 6. Process assertions
        assertions = parser.get_assertions()
        if not assertions:
            raise SAMLError("No assertions found in SAML Response")

        user_info = None
        for assertion in assertions:
            assertion_signed = False

            # Validate assertion signature if present
            assertion_sig = assertion.find("ds:Signature", NAMESPACES)
            if assertion_sig is not None:
                try:
                    self.signature_validator.validate_signature(assertion)
                    assertion_signed = True
                except SAMLError as e:
                    raise SAMLError(
                        f"Assertion signature validation failed: {e}"
                    )

            # At least one of Response or Assertion must be signed
            if not response_signed and not assertion_signed:
                raise SAMLError(
                    "Neither Response nor Assertion has a valid signature"
                )

            # Validate assertion issuer
            assertion_issuer = assertion.find("saml:Issuer", NAMESPACES)
            if assertion_issuer is not None:
                issuer_text = (
                    assertion_issuer.text.strip()
                    if assertion_issuer.text
                    else None
                )
                if issuer_text != self.config["idp_entity_id"]:
                    raise SAMLError(
                        f"Assertion Issuer mismatch. Expected: "
                        f"{self.config['idp_entity_id']}, Got: {issuer_text}"
                    )

            # Parse assertion details
            assertion_parser = SAMLAssertionParser(assertion)

            # Validate conditions
            conditions = assertion_parser.get_conditions()
            if conditions:
                self._validate_conditions(conditions)

            # Validate SubjectConfirmationData
            scd = assertion_parser.get_subject_confirmation_data()
            if scd:
                self._validate_subject_confirmation(scd, expected_request_id)

            # Extract user info
            name_id = assertion_parser.get_subject_name_id()
            attributes = assertion_parser.get_attributes()
            session_index = assertion_parser.get_session_index()

            user_info = {
                "name_id": name_id,
                "attributes": attributes,
                "session_index": session_index,
                "authn_context": assertion_parser.get_authn_context_class_ref(),
            }

        if user_info is None:
            raise SAMLError("Could not extract user information from assertions")

        return user_info

    def _validate_conditions(self, conditions):
        """Validate the Conditions element timing and audience."""
        now = datetime.now(timezone.utc)
        drift = self.config.get("accepted_time_drift_seconds", 120)

        if conditions.get("not_before"):
            not_before = self._parse_saml_datetime(conditions["not_before"])
            from datetime import timedelta
            if now < not_before - timedelta(seconds=drift):
                raise SAMLError(
                    f"Assertion not yet valid. NotBefore: {conditions['not_before']}"
                )

        if conditions.get("not_on_or_after"):
            not_on_or_after = self._parse_saml_datetime(
                conditions["not_on_or_after"]
            )
            from datetime import timedelta
            if now >= not_on_or_after + timedelta(seconds=drift):
                raise SAMLError(
                    f"Assertion has expired. NotOnOrAfter: {conditions['not_on_or_after']}"
                )

        if conditions.get("audiences"):
            if self.config["sp_entity_id"] not in conditions["audiences"]:
                raise SAMLError(
                    f"SP entity ID not in audience restriction. "
                    f"Expected: {self.config['sp_entity_id']}, "
                    f"Got: {conditions['audiences']}"
                )

    def _validate_subject_confirmation(self, scd, expected_request_id):
        """Validate SubjectConfirmationData."""
        now = datetime.now(timezone.utc)
        drift = self.config.get("accepted_time_drift_seconds", 120)

        if scd.get("not_on_or_after"):
            from datetime import timedelta
            not_on_or_after = self._parse_saml_datetime(scd["not_on_or_after"])
            if now >= not_on_or_after + timedelta(seconds=drift):
                raise SAMLError(
                    f"SubjectConfirmation has expired: {scd['not_on_or_after']}"
                )

        if scd.get("recipient"):
            if scd["recipient"] != self.config["sp_acs_url"]:
                raise SAMLError(
                    f"SubjectConfirmation Recipient mismatch. "
                    f"Expected: {self.config['sp_acs_url']}, Got: {scd['recipient']}"
                )

        if expected_request_id and scd.get("in_response_to"):
            if scd["in_response_to"] != expected_request_id:
                raise SAMLError(
                    f"SubjectConfirmation InResponseTo mismatch. "
                    f"Expected: {expected_request_id}, "
                    f"Got: {scd['in_response_to']}"
                )

    @staticmethod
    def _parse_saml_datetime(dt_string):
        """Parse a SAML datetime string to a timezone-aware datetime."""
        formats = [
            "%Y-%m-%dT%H:%M:%SZ",
            "%Y-%m-%dT%H:%M:%S.%fZ",
            "%Y-%m-%dT%H:%M:%S%z",
        ]
        for fmt in formats:
            try:
                dt = datetime.strptime(dt_string, fmt)
                if dt.tzinfo is None:
                    dt = dt.replace(tzinfo=timezone.utc)
                return dt
            except ValueError:
                continue
        raise SAMLError(f"Could not parse datetime: {dt_string}")

